add_action('wp_head','_rrq_faq_head',10);
function _rrq_faq_head(){
    if(!is_page())return;
    $slug=get_post_field('post_name',get_the_ID());
    $all=_rrq_city_faq_data();
    if(!isset($all[$slug]))return;
    $entities=array_map(function($f){return['@type'=>'Question','name'=>$f['q'],'acceptedAnswer'=>['@type'=>'Answer','text'=>$f['a']]];}, $all[$slug]['faqs']);
    echo '<script type="application/ld+json">'.json_encode(['@context'=>'https://schema.org','@type'=>'FAQPage','mainEntity'=>$entities],JSON_UNESCAPED_SLASHES|JSON_UNESCAPED_UNICODE).'</script>'."
";
    echo '<style id="rrq-faq-css">
.rrq-faq-section{background:#0d0d0d;padding:64px 20px;font-family:inherit;border-top:3px solid #cc0000}
.rrq-faq-inner{max-width:860px;margin:0 auto}
.rrq-faq-title{color:#c8a94e;font-size:clamp(20px,2.8vw,30px);font-weight:800;margin:0 0 32px;text-transform:uppercase;letter-spacing:1.5px;text-align:center}
.rrq-faq-list{display:flex;flex-direction:column;gap:10px;margin-bottom:36px}
.rrq-faq-item{background:#161616;border:1px solid #2a2a2a;border-radius:8px;overflow:hidden}
.rrq-faq-item[open]{border-color:#c8a94e66}
.rrq-faq-q{display:flex;justify-content:space-between;align-items:center;gap:14px;cursor:pointer;padding:18px 22px;color:#f0f0f0;font-size:15.5px;font-weight:600;line-height:1.45;list-style:none}
.rrq-faq-q::-webkit-details-marker{display:none}
.rrq-faq-q:hover,.rrq-faq-item[open]>.rrq-faq-q{color:#c8a94e}
.rrq-faq-icon{flex-shrink:0;width:24px;height:24px;position:relative}
.rrq-faq-icon::before,.rrq-faq-icon::after{content:"";position:absolute;background:#c8a94e;border-radius:2px;transition:transform .25s,opacity .25s}
.rrq-faq-icon::before{width:2px;height:14px;top:5px;left:11px}
.rrq-faq-icon::after{width:14px;height:2px;top:11px;left:5px}
.rrq-faq-item[open] .rrq-faq-icon::before{transform:rotate(90deg);opacity:0}
.rrq-faq-a{padding:0 22px 20px;color:#bbb;font-size:15px;line-height:1.75}
.rrq-faq-a p{margin:0}
.rrq-faq-cta{text-align:center}
.rrq-faq-btn{display:inline-block;background:#cc0000;color:#fff!important;text-decoration:none!important;padding:14px 40px;border-radius:6px;font-weight:700;font-size:16px;transition:background .2s,transform .15s;box-shadow:0 4px 14px rgba(204,0,0,.35)}
.rrq-faq-btn:hover{background:#a80000;transform:translateY(-2px)}
@media(max-width:600px){.rrq-faq-section{padding:44px 14px}.rrq-faq-title{font-size:18px}.rrq-faq-q{font-size:14px;padding:14px 16px}.rrq-faq-a{padding:0 16px 16px}}
</style>';
}

add_filter('the_content','_rrq_faq_content',20);
function _rrq_faq_content($content){
    if(!is_main_query()||!in_the_loop()||!is_page())return $content;
    $slug=get_post_field('post_name',get_the_ID());
    $all=_rrq_city_faq_data();
    if(!isset($all[$slug]))return $content;
    $city=esc_html($all[$slug]['city']);
    $h='<section class="rrq-faq-section" aria-labelledby="rrq-faq-h"><div class="rrq-faq-inner">';
    $h.='<h2 id="rrq-faq-h" class="rrq-faq-title">Frequently Asked Questions &mdash; Roofing in '.$city.', Utah</h2>';
    $h.='<div class="rrq-faq-list">';
    foreach($all[$slug]['faqs'] as $i=>$f){
        $h.='<details class="rrq-faq-item"'.($i===0?' open':'').'>';
        $h.='<summary class="rrq-faq-q">'.esc_html($f['q']).'<span class="rrq-faq-icon" aria-hidden="true"></span></summary>';
        $h.='<div class="rrq-faq-a"><p>'.esc_html($f['a']).'</p></div>';
        $h.='</details>';
    }
    $h.='</div><div class="rrq-faq-cta"><a href="/roof-quote/" class="rrq-faq-btn">Get a Free Roof Estimate &rarr;</a></div>';
    $h.='</div></section>';
    return $content.$h;
}